interface Animal {
  name: string;
}

interface Cat extends Animal {
  purr(): void;
}

type HandleAnimal = (a: Animal) => void;
type HandleCat = (a: Cat) => void;

const handleAnimal: HandleAnimal = (a) => {
  console.log(a.name); // Использует только name
};

const handleCat: HandleCat = (a) => {
  a.purr(); // Использует purr -- специфичный для Cat
  console.log(a.name);
};

let catHandler: HandleCat;

// Присваиваем обработчик Animal в позицию обработчика Cat
catHandler = handleAnimal; // OK!

// Безопасно: catHandler будет вызван с Cat,
// а handleAnimal принимает любой Animal.
// Cat -- это Animal, значит handleAnimal справится.
const myCat: Cat = { name: 'Мурка', purr() {} };
catHandler(myCat); // OK -- handleAnimal использует только name

let animalHandler: HandleAnimal;

// Присваиваем обработчик Cat в позицию обработчика Animal
// animalHandler = handleCat; // Ошибка при strictFunctionTypes!

// Почему это опасно:
const dog: Animal = { name: 'Шарик' };
// animalHandler(dog); // handleCat вызовет dog.purr()
// Но у dog нет purr() -- runtime error!

// Иерархия типов:
//   Cat <: Animal (Cat -- подтип Animal)
//
// Иерархия функций (при strict):
//   HandleAnimal <: HandleCat (направление инвертировано!)
//
// Ковариантность:  Cat <: Animal => Producer<Cat> <: Producer<Animal>
// Контравариантность: Cat <: Animal => Consumer<Animal> <: Consumer<Cat>
